mapper.select:
SELECT id, ticket_type_id, channel, allocated, sold
FROM ticket_inventory
WHERE ticket_type_id = #{ticketTypeId}
  AND channel = #{channel}

mapper.update:
UPDATE ticket_inventory
SET sold = sold + #{quantity}
WHERE ticket_type_id = #{ticketTypeId}
  AND channel = #{channel}
  AND sold + #{quantity} <= allocated

UPDATE ticket_inventory
SET sold = IF(sold - #{quantity} < 0, 0, sold - #{quantity})
WHERE ticket_type_id = #{ticketTypeId}
  AND channel = #{channel}
